import"./ticker-BxUDbM2L.js";import{i as e}from"./country-page-CK6BdUjw.js";/* empty css                  */import"./utils-Owvk3OYq.js";import"./breadcrumbs-CxxVGuAV.js";e({navDepth:2,breadcrumbParent:{label:"UAE Gold",url:"../../uae.html"},countryCode:"AE",currency:"AED",flag:"🇦🇪",nameEn:"Abu Dhabi, UAE",nameAr:"أبوظبي، الإمارات",fixedPeg:!0,decimals:2,timezone:"Asia/Dubai",relatedCountries:[{file:"../../uae.html",nameEn:"UAE Overview",nameAr:"نظرة عامة — الإمارات",flag:"🇦🇪"},{file:"../../saudi-arabia.html",nameEn:"Saudi Arabia",nameAr:"السعودية",flag:"🇸🇦"},{file:"../../qatar.html",nameEn:"Qatar",nameAr:"قطر",flag:"🇶🇦"},{file:"../../kuwait.html",nameEn:"Kuwait",nameAr:"الكويت",flag:"🇰🇼"},{file:"../../oman.html",nameEn:"Oman",nameAr:"عُمان",flag:"🇴🇲"}],faqEn:[{q:"What is the gold price in Abu Dhabi today?",a:"Abu Dhabi uses the UAE Dirham (AED), which is fixed at 3.6725 per USD. The gold price shown above is updated every 90 seconds and reflects the current global spot rate converted to AED. The rate is identical to Dubai as both cities use the same currency at the same peg."},{q:"Is gold cheaper in Abu Dhabi than in Dubai?",a:"The base metal price is identical in both cities — both use AED at the same fixed peg. The difference is in making charges and shop-specific margins. Abu Dhabi's Madinat Zayed Gold Center is competitive, though Dubai's Gold Souk has a larger density of traders and more negotiation scope."},{q:"Where is the best place to buy gold in Abu Dhabi?",a:"Madinat Zayed Gold Center is the most established destination, offering a wide range of retailers in one complex. Hamdan Street area is good for comparison shopping. For branded retailers, Yas Mall or Abu Dhabi Mall are convenient options."},{q:"What is the VAT on gold in Abu Dhabi?",a:"UAE VAT applies equally across all emirates: 5% on jewellery, zero-rated on investment gold (bars and coins meeting purity standards). Tourists can reclaim VAT through the Federal Tax Authority's tourist refund scheme at Abu Dhabi International Airport."}],faqAr:[{q:"ما هو سعر الذهب في أبوظبي اليوم؟",a:"تستخدم أبوظبي الدرهم الإماراتي المرتبط بسعر ثابت 3.6725 درهم للدولار. يتم تحديث السعر أعلاه كل 90 ثانية."},{q:"هل الذهب في أبوظبي أرخص من دبي؟",a:"سعر المعدن الأساسي متطابق في كلتا المدينتين إذ تستخدمان نفس العملة والسعر الثابت. الفرق يكمن في أجرة الصنعة وهوامش كل محل."},{q:"أين أفضل مكان لشراء الذهب في أبوظبي؟",a:"مركز ماديناتي زايد للذهب هو الوجهة الرئيسية، حيث يتيح مقارنة الأسعار بين عشرات التجار في مجمع واحد. شارع حمدان يوفر أيضاً مجموعة متنوعة من المحلات."}]});
